VALUES ('weekly_report', 'running', NOW())
RETURNING id;

parameters.jsCode:
const topPages = $('Top Pages by Click Growth').all().map(i => i.json);
const nearPageOne = $('Near Page One Queries').all().map(i => i.json);
const opportunities = $('Top Content Opportunities').all().map(i => i.json);

const today = new Date().toLocaleDateString('he-IL');

// Helper to shorten URL
const shortUrl = url => url.replace('https://www.perfect1.co.il', '');

// Build WhatsApp text report (plain text, not HTML, for WA compatibility)
let report = `*דוח SEO שבועי — perfect1.co.il*\n`;
report += `📅 ${today}\n\n`;

report += `*📈 עמודים מובילים לפי קליקים (7 ימים):*\n`;
topPages.slice(0, 5).forEach((p, i) => {
  const growth = p.clicks_prev_week > 0
    ? Math.round((p.clicks_this_week - p.clicks_prev_week) / p.clicks_prev_week * 100)
    : 100;
  const arrow = growth >= 0 ? '↑' : '↓';
  report += `${i+1}. ${shortUrl(p.page_url)}\n   ${p.clicks_this_week} קליקים ${arrow}${Math.abs(growth)}%\n`;
});

report += `\n*🎯 שאילתות קרובות לעמוד 1:*\n`;
nearPageOne.slice(0, 10).forEach((q, i) => {
  report += `${i+1}. "${q.query}" — מיקום ${q.avg_position} (${q.total_impressions} חשיפות)\n`;
});

report += `\n*💡 הזדמנויות תוכן:*\n`;
opportunities.slice(0, 5).forEach((o, i) => {
  const type = {
    near_page_one: 'קרוב לעמוד 1',
    rising_page: 'עמוד עולה',
    high_imp_low_ctr: 'CTR נמוך',
    commercial_intent: 'כוונה מסחרית',
    cluster_traction: 'קלאסטר'
  }[o.opportunity_type] || o.opportunity_type;
  report += `${i+1}. ${type}: ${o.query || shortUrl(o.page_url)} (ציון: ${o.priority_score})\n`;
});

report += `\n✅ דוח מלא ב-Supabase: seo_opportunities`;

// HTML version for email
let html = `<div dir="rtl" style="font-family:Arial,sans-serif;max-width:700px">`;
html += `<h2>דוח SEO שבועי — perfect1.co.il</h2><p>תאריך: ${today}</p>`;

html += `<h3>עמודים מובילים</h3><table border="1" cellpadding="5" style="border-collapse:collapse;width:100%">`;
html += `<tr><th>עמוד</th><th>קליקים</th><th>שינוי</th></tr>`;
topPages.forEach(p => {
  const growth = p.clicks_prev_week > 0 ? Math.round((p.clicks_this_week - p.clicks_prev_week) / p.clicks_prev_week * 100) : 100;
  html += `<tr><td>${shortUrl(p.page_url)}</td><td>${p.clicks_this_week}</td><td>${growth >= 0 ? '+' : ''}${growth}%</td></tr>`;
});
html += `</table>`;

html += `<h3>שאילתות קרובות לעמוד 1</h3><table border="1" cellpadding="5" style="border-collapse:collapse;width:100%">`;
html += `<tr><th>שאילתה</th><th>מיקום</th><th>חשיפות</th></tr>`;
nearPageOne.forEach(q => {
  html += `<tr><td>${q.query}</td><td>${q.avg_position}</td><td>${q.total_impressions}</td></tr>`;
});
html += `</table></div>`;

return [{ json: { report_text: report, report_html: html, run_id: $('Set Run ID').first().json.run_id } }];
